rue,true) self.AirCombo = false else AttackEvent:FireServer("Hitbox",nil,script:WaitForChild("Server"):WaitForChild("Handler"):WaitForChild("MidHit"),5,self.HSize,true,false) end end) end delay(self.HitWait,function() if self.Combo == 1 then AttackEvent:FireServer("Hitbox",nil,script:WaitForChild("Server"):WaitForChild("Handler"):WaitForChild("MidHit"),5,self.HSize,false,false) elseif self.Combo == 2 then AttackEvent:FireServer("Hitbox",nil,script:WaitForChild("Server"):WaitForChild("Handler"):WaitForChild("MidHit"),5,self.HSize,false,false) elseif self.Combo == 3 then AttackEvent:FireServer("Hitbox",nil,script:WaitForChild("Server"):WaitForChild("Handler"):WaitForChild("LeftHit"),5,self.HSize,false,false) elseif self.Combo == 4 then if self.SpaceHold == false then AttackEvent:FireServer("Hitbox",nil,script:WaitForChild("Server"):WaitForChild("Handler"):WaitForChild("RightHit"),5,self.HSize,false,false) else AttackEvent:FireServer("Hitbox",nil,script:WaitForChild("Server"):WaitForChild("Handler"):WaitForChild("RightHit"),5,self.HSize,false,true) self.AirCombo = true delay(1,function() self.AirCombo = false end) end end print("Done") end) local function reset() if self.Combo >= self.MaxCombo then self.Combo = 0 delay(self.LastCooldownTime,function() self.PunchDebounce = false end) end end local function reset2() if self.Combo >= self.MaxCombo then self.Combo = 0 delay(self.HitDelay,function() self.PunchDebounce = false end) end end local function reset3() local Combo = self.Combo delay(self.ResetTime,function() if Combo == self.Combo then self.Combo = 0 end end) end reset3() if self.LastCooldown == true then reset() else reset2() end end end return HitboxSettings 

