 local Players = game:GetService("Players") local ReplicatedStorage = game:GetService("ReplicatedStorage") local TweenService = game:GetService("TweenService") local RunService = game:GetService("RunService") local UserInputService = game:GetService("UserInputService") local player = Players.LocalPlayer local playerGui = player:WaitForChild("PlayerGui") local PotionArrowGuide = ReplicatedStorage:WaitForChild("PotionArrowGuide", 10) if not PotionArrowGuide then warn("?? PotionArrowGuide remote not found") return end print("?? POTION ARROW GUIDE CLIENT LOADED") local activeArrows = {} local arrowConnections = {} local arrowEndTime = 0 local function createArrowGUI() local gui = Instance.new("ScreenGui") gui.Name = "PotionArrowGui" gui.ResetOnSpawn = false gui.Parent = playerGui return gui end local arrowGui = createArrowGUI() local function createSingleArrow(targetPosition, potionName, duration, potionId) print("?? Creating arrow guide to: " .. tostring(targetPosition) .. " for " .. duration .. " seconds (ID: " .. tostring(potionId) .. ")") local activeArrow = Instance.new("Frame") activeArrow.Name = "PotionArrow_" .. tostring(potionId) activeArrow.Size = UDim2.new(0, 70, 0, 70) activeArrow.Position = UDim2.new(0.5, -35, 0.5, -35) activeArrow.BackgroundTransparency = 1 activeArrow.Parent = arrowGui local arrowIcon = Instance.new("TextLabel") arrowIcon.Name = "ArrowIcon" arrowIcon.Size = UDim2.new(0, 42, 0, 42) arrowIcon.Position = UDim2.new(0.5, -21, 0.5, -21) arrowIcon.BackgroundTransparency = 1 arrowIcon.Text = "??" arrowIcon.TextColor3 = Color3.fromRGB(255, 215, 0) arrowIcon.TextSize = 25 arrowIcon.Font = Enum.Font.Arcade arrowIcon.TextStrokeTransparency = 0.3 arrowIcon.TextStrokeColor3 = Color3.fromRGB(0, 0, 0) arrowIcon.Parent = activeArrow local arrowPointer = Instance.new("TextLabel") arrowPointer.Name = "ArrowPointer" arrowPointer.Size = UDim2.new(0, 28, 0, 28) arrowPointer.Position = UDim2.new(0.5, -14, 0, -32) arrowPointer.BackgroundTransparency = 1 arrowPointer.Text = "?" arrowPointer.TextColor3 = Color3.fromRGB(255, 100, 255) arrowPointer.TextSize = 17 arrowPointer.Font = Enum.Font.Arcade arrowPointer.TextStrokeTransparency = 0.3 arrowPointer.TextStrokeColor3 = Color3.fromRGB(0, 0, 0) arrowPointer.Parent = activeArrow local distanceText = Instance.new("TextLabel") distanceText.Name = "DistanceText" distanceText.Size = UDim2.new(0, 70, 0, 18) distanceText.Position = UDim2.new(0.5, -35, 1, 4) distanceText.BackgroundTransparency = 1 distanceText.Text = "0m" distanceText.TextColor3 = Color3.fromRGB(255, 255, 255) distanceText.TextSize = 12 distanceText.Font = Enum.Font.Arcade distanceText.TextStrokeTransparency = 0.3 distanceText.TextStrokeColor3 = Color3.fromRGB(0, 0, 0) distanceText.Parent = activeArrow local timerText = Instance.new("TextLabel") timerText.Name = "TimerText" timerText.Size = UDim2.new(0, 70, 0, 14) timerText.Position = UDim2.new(0.5, -35, 1, 22) timerText.BackgroundTransparency = 1 timerText.Text = duration .. "s" timerText.TextColor3 = Color3.fromRGB(255, 215, 0) timerText.TextSize = 10 timerText.Font = Enum.Font.Arcade timerText.TextStrokeTransparency = 0.3 timerText.TextStrokeColor3 = Color3.fromRGB(0, 0, 0) timerText.Parent = activeArrow local glowFrame = Instance.new("Frame") glowFrame.Name = "ArrowGlow" glowFrame.Size = UDim2.new(1, 14, 1, 14) glowFrame.Position = UDim2.new(0, -7, 0, -7) glowFrame.BackgroundColor3 = Color3.fromRGB(255, 100, 255) glowFrame.BackgroundTransparency = 0.7 glowFrame.BorderSizePixel = 0 glowFrame.ZIndex = activeArrow.ZIndex - 1 glowFrame.Parent = activeArrow local glowCorner = Instance.new("UICorner") glowCorner.CornerRadius = UDim.new(1, 0) glowCorner.Parent = glowFrame activeArrows[potionId] = { frame = activeArrow, targetPosition = targetPosition, potionName = potionName, endTime = tick() + duration } spawn(function() while activeArrows[potionId] and activeArrows[potionId].frame and activeArrows[potionId].frame.Parent and tick() < activeArrows[potionId].endTime do local pulse1 = TweenService:Create(glowFrame, TweenInfo.new(0.8, Enum.EasingStyle.Sine), { BackgroundTransparency = 0.5, Size = UDim2.new(1, 18, 1, 18) }) local pulse2 = TweenService:Create(glowFrame, TweenInfo.new(0.8, Enum.EasingStyle.Sine), { BackgroundTransparency = 0.8, Size = UDim2.new(1, 10, 1, 10) }) pulse1:Play() pulse1.Completed:Wait() pulse2:Play() pulse2.Completed:Wait() end end) spawn(function() while activeArrows[potionId] and activeArrows[potionId].frame and activeArrows[potionId].frame.Parent and tick() < activeArrows[potionId].endTime do local iconPulse1 = TweenService:Create(arrowIcon, TweenInfo.new(1, Enum.EasingStyle.Sine), { TextSize = 28 }) local iconPulse2 = TweenService:Create(arrowIcon, TweenInfo.new(1, Enum.EasingStyle.Sine), { TextSize = 25 }) iconPulse1:Play() iconPulse1.Completed:Wait() iconPulse2:Play() iconPulse2.Completed:Wait() end end) activeArrow.Size = UDim2.new(0, 0, 0, 0) local enterTween = TweenService:Create(activeArrow, TweenInfo.new(0.5, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {Size = UDim2.new(0, 70, 0, 70)} ) enterTween:Play() return activeArrow end local function removeArrow(potionId) if activeArrows[potionId] then local arrowData = activeArrows[potionId] if arrowData.frame then local fadeOut = TweenService:Create(arrowData.frame, TweenInfo.new(0.5, Enum.EasingStyle.Quad), { Size = UDim2.new(0, 0, 0, 0) }) fadeOut:Play() fadeOut.Completed:Connect(function() if arrowData.frame then arrowData.frame:Destroy() end end) end activeArrows[potionId] = nil end end local function createMultipleArrows(potionsData) print("?? Creating arrows for " .. #potionsData .. " potions") for potionId, _ in pairs(activeArrows) do removeArrow(potionId) end for _, connection in pairs(arrowConnections) do if connection then connection:Disconnect() end end arrowConnections = {} for i, potionData in ipairs(potionsData) do if potionData.targetPosition and potionData.duration then local potionId = potionData.potionId or ("potion_" .. i) createSingleArrow(potionData.targetPosition, potionData.potionName or "Luck Potion", potionData.duration, potionId) end end local masterConnection masterConnection = RunService.Heartbeat:Connect(function() local currentTime = tick() local arrowsToRemove = {} for potionId, arrowData in pairs(activeArrows) do local activeArrow = arrowData.frame local targetPosition = arrowData.targetPosition local timeLeft = arrowData.endTime - currentTime if not activeArrow or not activeArrow.Parent or timeLeft <= 0 then table.insert(arrowsToRemove, potionId) else local timerText = activeArrow:FindFirstChild("TimerText") local distanceText = activeArrow:FindFirstChild("DistanceText") local arrowIcon = activeArrow:FindFirstChild("ArrowIcon") local arrowPointer = activeArrow:FindFirstChild("ArrowPointer") if timerText then timerText.Text = math.ceil(timeLeft) .. "s" if timeLeft <= 3 then timerText.TextColor3 = Color3.fromRGB(255, 100, 100) elseif timeLeft <= 6 then timerText.TextColor3 = Color3.fromRGB(255, 200, 100) else timerText.TextColor3 = Color3.fromRGB(255, 215, 0) end end local character = player.Character if character and character:FindFirstChild("HumanoidRootPart") then local playerPosition = character.HumanoidRootPart.Position local camera = workspace.CurrentCamera if camera then local directionVector = (targetPosition - playerPosition).Unit local distance = (targetPosition - playerPosition).Magnitude if distanceText then distanceText.Text = math.floor(distance) .. "m" end local baseOffset = (tonumber(potionId:match("(%d+)")) or 0) * 80 local screenCenter = Vector2.new(camera.ViewportSize.X / 2, camera.ViewportSize.Y / 2) local worldToScreen, onScreen = camera:WorldToScreenPoint(targetPosition) if onScreen then local screenDirection = Vector2.new(worldToScreen.X - screenCenter.X, worldToScreen.Y - screenCenter.Y) local screenDistance = screenDirection.Magnitude if screenDistance > 100 then local normalizedDirection = screenDirection.Unit local arrowScreenPos = screenCenter + normalizedDirection * (150 + baseOffset * 0.3) activeArrow.Position = UDim2.new(0, arrowScreenPos.X - 35, 0, arrowScreenPos.Y - 35) if arrowPointer then local angle = math.atan2(normalizedDirection.Y, normalizedDirection.X) arrowPointer.Rotation = math.deg(angle) + 90 end else local offsetX = math.sin(baseOffset * 0.1) * 60 local offsetY = math.cos(baseOffset * 0.1) * 60 activeArrow.Position = UDim2.new(0.5, -35 + offsetX, 0.5, -35 + offsetY) if arrowPointer then arrowPointer.Rotation = 0 end end else local cameraLookDirection = camera.CFrame.LookVector local rightVector = camera.CFrame.RightVector local upVector = camera.CFrame.UpVector local relativeDirection = directionVector local screenX = relativeDirection:Dot(rightVector) local screenY = -relativeDirection:Dot(upVector) local screenDirection = Vector2.new(screenX, screenY).Unit local arrowScreenPos = screenCenter + screenDirection * 200 arrowScreenPos = Vector2.new( math.clamp(arrowScreenPos.X, 100, camera.ViewportSize.X - 100), math.clamp(arrowScreenPos.Y, 100, camera.ViewportSize.Y - 100) ) local offsetAngle = baseOffset * 0.2 local offsetRadius = 30 arrowScreenPos = arrowScreenPos + Vector2.new( math.cos(offsetAngle) * offsetRadius, math.sin(offsetAngle) * offsetRadius ) activeArrow.Position = UDim2.new(0, arrowScreenPos.X - 35, 0, arrowScreenPos.Y - 35) if arrowPointer then local angle = math.atan2(screenDirection.Y, screenDirection.X) arrowPointer.Rotation = math.deg(angle) + 90 end end if arrowIcon and arrowPointer then if distance < 20 then arrowIcon.TextColor3 = Color3.fromRGB(100, 255, 100) arrowPointer.TextColor3 = Color3.fromRGB(100, 255, 100) elseif distance < 50 then arrowIcon.TextColor3 = Color3.fromRGB(255, 255, 100) arrowPointer.TextColor3 = Color3.fromRGB(255, 255, 100) else arrowIcon.TextColor3 = Color3.fromRGB(255, 215, 0) arrowPointer.TextColor3 = Color3.fromRGB(255, 100, 255) end end end end end end for _, potionId in ipairs(arrowsToRemove) do removeArrow(potionId) end if next(activeArrows) == nil then masterConnection:Disconnect() end end) table.insert(arrowConnections, masterConnection) end PotionArrowGuide.OnClientEvent:Connect(function(guideData) print("?? Received arrow guide request: " .. tostring(guideData)) if guideData then if guideData.potions and type(guideData.potions) == "table" then createMultipleArrows(guideData.potions) elseif guideData.targetPosition and guideData.duration then createMultipleArrows({{ targetPosition = guideData.targetPosition, potionName = guideData.potionName or "Luck Potion", duration = guideData.duration, potionId = "single_potion" }}) else warn("?? Invalid guide data received") end else warn("?? No guide data received") end end) player.CharacterAdded:Connect(function() wait(2) end) print("?? ?? Potion Arrow Guide System loaded!") print("?? Matteoooo's VIP players will receive 12-second arrow guidance to ALL potions!")

