lor3 = Color3.fromRGB(0, 0, 0) subLabel.TextScaled = true subLabel.Parent = btn end return btn end local quickBtn local function updateQuickButtonAppearance() if not quickBtn then return end local mainLabel = quickBtn:FindFirstChild("MainLabel") local subLabel = quickBtn:FindFirstChild("SubLabel") if not mainLabel or not subLabel then return end print("?? Updating Quick Roll button - hasGamepass: " .. tostring(hasQuickRollGamepass) .. ", enabled: " .. tostring(quickRollEnabled)) if hasQuickRollGamepass then if quickRollEnabled then mainLabel.Text = "Quick roll : ON" mainLabel.TextColor3 = Color3.fromRGB(120, 255, 120) subLabel.Text = "*Faster rolling!" subLabel.TextColor3 = Color3.fromRGB(120, 255, 120) else mainLabel.Text = "Quick roll : OFF" mainLabel.TextColor3 = Color3.fromRGB(255, 255, 255) subLabel.Text = "*Gamepass owned" subLabel.TextColor3 = Color3.fromRGB(120, 200, 255) end else mainLabel.Text = "Quick roll : LOCKED" mainLabel.TextColor3 = Color3.fromRGB(200, 100, 100) subLabel.Text = "*Click to buy!" subLabel.TextColor3 = Color3.fromRGB(255, 150, 150) if not gamepassCheckInProgress then quickRollEnabled = false end end end local function checkQuickRollOwnership(forceCheck) local currentTime = tick() if not forceCheck and (gamepassCheckInProgress or (currentTime - lastGamepassCheck) < 2) then print("?? Gamepass check skipped - too recent or in progress") return hasQuickRollGamepass end gamepassCheckInProgress = true lastGamepassCheck = currentTime print("?? Checking gamepass ownership... (forced: " .. tostring(forceCheck or false) .. ")") local success, owns = pcall(function() return MarketplaceService:UserOwnsGamePassAsync(player.UserId, QUICK_ROLL_GAMEPASS_ID) end) if success then local previousState = hasQuickRollGamepass hasQuickRollGamepass = owns print("?? Quick Roll gamepass check result: " .. (owns and "OWNED" or "NOT OWNED")) if hasQuickRollGamepass and not quickRollEnabled and previousState ~= hasQuickRollGamepass then print("?? Re-enabling Quick Roll since gamepass is owned") quickRollEnabled = true end if previousState ~= hasQuickRollGamepass then print("?? Gamepass ownership changed from " .. tostring(previousState) .. " to " .. tostring(hasQuickRollGamepass)) updateQuickButtonAppearance() end else warn("?? Failed to check Quick Roll gamepass ownership") end gamepassCheckInProgress = false return hasQuickRollGamepass end local function promptQuickRollPurchase() print("?? Prompting Quick Roll gamepass purchase...") local success, error = pcall(function() MarketplaceService:PromptGamePassPurchase(player, QUICK_ROLL_GAMEPASS_ID) end) if not success then warn("?? Failed to prompt gamepass purchase: " .. tostring(error)) end end MarketplaceService.PromptGamePassPurchaseFinished:Connect(function(playerWho, gamepassId, wasPurchased) if playerWho == player and gamepassId == QUICK_ROLL_GAMEPASS_ID then print("?? Purchase prompt finished - wasPurchased: " .. tostring(wasPurchased)) if wasPurchased then print("?? Quick Roll gamepass purchased successfully!") hasQuickRollGamepass = true quickRollEnabled = true local mainLabel = quickBtn:FindFirstChild("MainLabel") local subLabel = quickBtn:FindFirstChild("SubLabel") if mainLabel and subLabel then mainLabel.Text = "PURCHASED!" mainLabel.TextColor3 = Color3.fromRGB(120, 255, 120) subLabel.Text = "*Now enabled!" subLabel.TextColor3 = Color3.fromRGB(120, 255, 120) spawn(function() wait(3) updateQuickButtonAppearance() end) end else print("? Quick Roll gamepass purchase cancelled") updateQuickButtonAppearance() end end end) local autoBtn = createButton( container, UDim2.new(0, 220, 0, 70), UDim2.new(0, 0, 0, 10), "Auto roll : OFF", "*Group join required", false ) local rollBtn = createButton( container, UDim2.new(0, 260, 0, 90), UDim2.new(0, 245, 0, 0), "Roll", "1/10", true ) quickBtn = createButton( container, UDim2.new(0, 220, 0, 70), UDim2.new(0, 530, 0, 10), "Quick roll : CHECKING", "*Loading...", false ) local function showRollCooldown(duration) local mainLabel = rollBtn:FindFirstChild("MainLabel") if not mainLabel then return end local originalText = mainLabel.Text local startTime = tick() spawn(function() while tick() - startTime < duration and rollButtonCooldown do local remaining = math.ceil(duration - (tick() - startTime)) mainLabel.Text = "Cooldown: " .. remaining .. "s" mainLabel.TextColor3 = Color3.fromRGB(255, 100, 100) wait(0.1) end if not rollButtonCooldown then mainLabel.Text = originalText mainLabel.TextColor3 = Color3.fromRGB(255, 255, 255) end end) end local function performRoll(isAutoRoll, isQuick) if _G.canRoll and not _G.canRoll() then if not isAutoRoll then print("Cannot roll - already rolling!") end return false end local quickRollWasEnabled = quickRollEnabled local gamepassWasOwned = hasQuickRollGamepass print("?? Starting roll - Quick Roll enabled: " .. tostring(quickRollWasEnabled) .. ", Gamepass owned: " .. tostring(gamepassWasOwned)) local subLabel = rollBtn:FindFirstChild("SubLabel") local mainLabel = rollBtn:FindFirstChild("MainLabel") if not isAutoRoll or not autoRollRunning then rollButtonCooldown = true if not quickRollEnabled then showRollCooldown(2) else showRollCooldown(0.5) end end local isLuckyRoll = (rollCount == 10) if isLuckyRoll then _G.luckBoostActive = true _G.luckBoostMultiplier = luckBoostMultiplier if subLabel then subLabel.Text = "? LUCKY ROLL!" subLabel.TextColor3 = Color3.fromRGB(255, 215, 0) end print("? LUCKY 10/10 ROLL! This roll has " .. luckBoostMultiplier .. "x better odds for rare items!") end wait(0.1) if _G.createRollPopup then _G.createRollPopup(isQuick or false) else local rollEvent = ReplicatedStorage:FindFirstChild("RollEvent") if not rollEvent then rollEvent = Instance.new("BindableEvent") rollEvent.Name = "RollEvent" rollEvent.Parent = ReplicatedStorage end rollEvent:Fire() end if rollCount == 10 then rollCount = 1 if subLabel then subLabel.Text = "1/10" subLabel.TextColor3 = Color3.fromRGB(120, 200, 255) end _G.luckBoostActive = false _G.luckBoostMultiplier = 1 else rollCount = rollCount + 1 if subLabel then subLabel.Text = rollCount .. "/10" end end spawn(function() local cooldownTime = quickRollWasEnabled and 0.5 or 2 wait(cooldownTime) if gamepassWasOwned and not hasQuickRollGamepass then print("?? Restoring gamepass ownership after roll") hasQuickRollGamepass = gamepassWasOwned end if gamepassWasOwned and quickRollWasEnabled and not quickRollEnabled then print("?? Restoring Quick Roll enabled state after roll") quickRollEnabled = quickRollWasEnabled updateQuickButtonAppearance() end rollButtonCooldown = false if mainLabel and mainLabel.Text:find("Cooldown") then mainLabel.Text = "Roll" mainLabel.TextColor3 = Color3.fromRGB(255, 255, 255) end if not isAutoRoll then print("Roll button ready!") end end) return true end local function startAutoRoll() if autoRollRunning then return end autoRollRunning = true spawn(function() while autoRollEnabled and autoRollRunning do if not rollButtonCooldown then local success = performRoll(true, quickRollEnabled) if success then local waitTime = quickRollEnabled and 1.5 or 4 wait(waitTime) else wait(1) end else wait(0.5) end end autoRollRunning = false print("Auto roll stopped") end) end autoBtn.MouseButton1Click:Connect(function() if autoRollCooldown then return end autoRollCooldown = true autoRollEnabled = not autoRollEnabled local mainLabel = autoBtn:FindFirstChild("MainLabel") if autoRollEnabled then mainLabel.Text = "Auto roll : ON" mainLabel.TextColor3 = Color3.fromRGB(120, 255, 120) print("Auto roll enabled") startAutoRoll() else mainLabel.Text = "Auto roll : OFF" mainLabel.TextColor3 = Color3.fromRGB(255, 255, 255) print("Auto roll disabled") autoRollRunning = false end spawn(function() task.wait(2) autoRollCooldown = false end) end) quickBtn.MouseButton1Click:Connect(function() if quickRollCooldown then return end quickRollCooldown = true print("??? Quick Roll button clicked - Current state: hasGamepass=" .. tostring(hasQuickRollGamepass) .. ", enabled=" .. tostring(quickRollEnabled)) if hasQuickRollGamepass then quickRollEnabled = not quickRollEnabled print("?? Toggling Quick Roll: " .. tostring(quickRollEnabled)) updateQuickButtonAppearance() if quickRollEnabled then print("?? Quick roll enabled - Faster rolling!") else print("?? Quick roll disabled") end else print("?? Double-checking gamepass ownership before purchase prompt...") local ownsGamepass = checkQuickRollOwnership(true) if ownsGamepass then quickRollEnabled = true updateQuickButtonAppearance() print("?? Quick roll enabled - Gamepass verified!") else print("?? Player doesn't own Quick Roll gamepass - prompting purchase") local mainLabel = quickBtn:FindFirstChild("MainLabel") local subLabel = quickBtn:FindFirstChild("SubLabel") if mainLabel and subLabel then mainLabel.Text = "Opening shop..." mainLabel.TextColor3 = Color3.fromRGB(255, 255, 100) subLabel.Text = "*Quick Roll - 50 R$" subLabel.TextColor3 = Color3.fromRGB(255, 255, 100) end promptQuickRollPurchase() spawn(function() wait(3) updateQuickButtonAppearance() end) end end spawn(function() task.wait(2) quickRollCooldown = false end) end) rollBtn.MouseButton1Click:Connect(function() if rollButtonCooldown then print("Roll button on cooldown!") return end if autoRollEnabled and not autoRollRunning then print("Starting auto roll sequence...") startAutoRoll() else performRoll(false, quickRollEnabled) end end) spawn(function() wait(3) print("?? Initial gamepass ownership check...") checkQuickRollOwnership(true) updateQuickButtonAppearance() end) spawn(function() while wait(60) do if not hasQuickRollGamepass then print("?? Periodic gamepass check (player doesn't own)") checkQuickRollOwnership(false) end end end) print("?? Enhanced Roll System with STATE PERSISTENCE FIXES loaded!") print("?? Quick Roll Gamepass ID: " .. QUICK_ROLL_GAMEPASS_ID) print("?? Critical fixes applied:") print(" - State preservation after rolling") print(" - Protected against unwanted resets") print(" - Better gamepass ownership persistence")

-- LocalScript: StarterGui>RollGui>RollPopUpScript

 local player = game.Players.LocalPlayer local playerGui = player:WaitForChild("PlayerGui") local ReplicatedStorage = game:GetService("ReplicatedStorage") local Debris = game:GetService("Debris") local TweenService = game:GetService("TweenService") local BrainrotDefinitions = require(ReplicatedStorage:WaitForChild("BrainrotDefinitions")) local brainrotItems = BrainrotDefinitions.List local BrainrotSounds = ReplicatedStorage:WaitForChild("BrainrotSounds") if playerGui:FindFirstChild("RollPopupGui") then playerGui.RollPopupGui:Destroy() end local gui = Instance.new("ScreenGui") gui.Name = "RollPopupGui" gui.IgnoreGuiInset = true gui.ResetOnSpawn = false gui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling gui.Parent = playerGui local isRolling = false local inventoryRemotes = nil local currentRollSound = nil local function waitForInventorySystem() local maxWait = 10 local waited = 0 while not inventoryRemotes and waited < maxWait do inventoryRemotes = ReplicatedStorage:FindFirstChild("InventoryRemotes") if not inventoryRemotes then wait(0.5) waited = waited + 0.5 end end return inventoryRemotes ~= nil end spawn(function() local success = waitForInventorySystem() if success then print("? Roll Popup: Inventory system connected") else warn("? Roll Popup: Inventory system not found") end end) local function addToInventory(itemName) if inventoryRemotes then local addItemEvent = inventoryRemotes:FindFirstChild("AddBrainrotItem") if addItemEvent then local success = pcall(function() addItemEvent:FireServer(itemName) end) if success then print("? Roll Popup: Added " .. itemName .. " to inventory") return true else warn("? Roll Popup: Failed to add " .. itemName .. " to inventory") end else warn("? Roll Popup: AddBrainrotItem event not found") end else warn("? Roll Popup: Inventory remotes not available") end return false end local BrainrotSettingsRemotes = ReplicatedStorage:WaitForChild("BrainrotSettingsRemotes") local skipBrainrotsValue = 0 local autoSaveValue = 0 local skipList = {} local saveList = {} local function fetchSettings() local success, settings = pcall(function() return BrainrotSettingsRemotes.RequestSettings:InvokeServer() end) if success and settings then skipBrainrotsValue = tonumber(settings.SkipBrainrots or 0) autoSaveValue = tonumber(settings.AutoSave or 0) skipList = settings.SkipList or {} saveList = settings.SaveList or {} print("? Roll Popup: Settings loaded") else warn("? Roll Popup: Failed to fetch settings") end end if BrainrotSettingsRemotes:FindFirstChild("UpdateSetting") then BrainrotSettingsRemotes.UpdateSetting.OnClientEvent:Connect(function(key, value) if key == "SkipBrainrots" then skipBrainrotsValue = tonumber(value) or 0 elseif key == "AutoSave" then autoSaveValue = tonumber(value) or 0 elseif key == "SkipList" then skipList = value or {} elseif key == "SaveList" then saveList = value or {} end print("?? Roll Popup: Setting updated - " .. key) end) end local function addCornerBrackets(parent, color) color = color or Color3.fromRGB(255, 255, 255) local thickness = 2 local length = 20 local tl1 = Instance.new("Frame") tl1.Size = UDim2.new(0, length, 0, thickness) tl1.Position = UDim2.new(0, 0, 0, 0) tl1.BackgroundColor3 = color tl1.BorderSizePixel = 0 tl1.ZIndex = parent.ZIndex + 1 tl1.Parent = parent local tl2 = Instance.new("Frame") tl2.Size = UDim2.new(0, thickness, 0, length) tl2.Position = UDim2.new(0, 0, 0, 0) tl2.BackgroundColor3 = color tl2.BorderSizePixel = 0 tl2.ZIndex = parent.ZIndex + 1 tl2.Parent = parent local tr1 = Instance.new("Frame") tr1.Size = UDim2.new(0, length, 0, thickness) tr1.Position = UDim2.new(1, -length, 0, 0) tr1.BackgroundColor3 = color tr1.BorderSizePixel = 0 tr1.ZIndex = parent.ZIndex + 1 tr1.Parent = parent local tr2 = Instance.new("Frame") tr2.Size = UDim2.new(0, thickness, 0, length) tr2.Position = UDim2.new(1, -thickness, 0, 0) tr2.BackgroundColor3 = color tr2.BorderSizePixel = 0 tr2.ZIndex = parent.ZIndex + 1 tr2.Parent = parent local bl1 = Instance.new("Frame") bl1.Size = UDim2.new(0, length, 0, thickness) bl1.Position = UDim2.new(0, 0, 1, -thickness) bl1.BackgroundColor3 = color bl1.BorderSizePixel = 0 bl1.ZIndex = parent.ZIndex + 1 bl1.Parent = parent local bl2 = Instance.new("Frame") bl2.Size = UDim2.new(0, thickness, 0, length) bl2.Position = UDim2.new(0, 0, 1, -length) bl2.BackgroundColor3 = color bl2.BorderSizePixel = 0 bl2.ZIndex = parent.ZIndex + 1 bl2.Parent = parent local br1 = Instance.new("Frame") br1.Size = UDim2.new(0, length, 0, thickness) br1.Position = UDim2.new(1, -length, 1, -thickness) br1.BackgroundColor3 = color br1.BorderSizePixel = 0 br1.ZIndex = parent.ZIndex + 1 br1.Parent = parent local br2 = Instance.new("Frame") br2.Size = UDim2.new(0, thickness, 0, length) br2.Position = UDim2.new(1, -thickness, 1, -length) br2.BackgroundColor3 = color br2.BorderSizePixel = 0 br2.ZIndex = parent.ZIndex + 1 br2.Parent = parent end local function getSFXVolume() return (_G.BrainrotSFXVolume or 1) * 2 end local function playSuspenseSound() local suspenseSoundTemplate = BrainrotSounds:FindFirstChild("RollSuspenseSound") if suspenseSoundTemplate then local sound = suspenseSoundTemplate:Clone() sound.Name = "ActiveRollSound" sound.Parent = workspace sound.Looped = true sound.Volume = getSFXVolume() sound:Play() currentRollSound = sound print("?? Roll Popup: Playing suspense sound") return sound else warn("? Roll Popup: Suspense sound not found") end return nil end local function stopSuspenseSound() if currentRollSound and currentRollSound:IsA("Sound") then currentRollSound:Stop() currentRollSound:Destroy() currentRollSound = nil print("?? Roll Popup: Stopped suspense sound") end for _, sound in ipairs(workspace:GetChildren()) do if sound:IsA("Sound") and sound.Name == "ActiveRollSound" then sound:Stop() sound:Destroy() end end end local function playBrainrotResultSound(brainrotName) local resultSoundTemplate = BrainrotSounds:FindFirstChild(brainrotName) if resultSoundTemplate and resultSoundTemplate:IsA("Sound") then local sound = resultSoundTemplate:Clone() sound.Name = "RollResultSound" sound.Parent = workspace sound.Looped = false sound.Volume = getSFXVolume() sound:Play() Debris:AddItem(sound, sound.TimeLength + 1) print("?? Roll Popup: Playing result sound for " .. brainrotName) else print("?? Roll Popup: No sound found for " .. brainrotName) end end local function playGuiClickSound() local clickSoundTemplate = BrainrotSounds:FindFirstChild("GuiClickSound") if clickSoundTemplate then local sound = clickSoundTemplate:Clone() sound.Volume = getSFXVolume() sound.Parent = workspace sound:Play() Debris:AddItem(sound, sound.TimeLength + 0.1) end end local function showFinalPopup(rolledItem, autoAction) stopSuspenseSound() playBrainrotResultSound(rolledItem.name) local existingPopup = gui:FindFirstChild("RollPopup") if existingPopup then existingPopup:Destroy() end local popup = Instance.new("Frame") popup.Name = "RollPopup" popup.Size = UDim2.new(0, 500, 0, 300) popup.Position = UDim2.new(0.5, -250, 0.5, -150) popup.BackgroundColor3 = Color3.fromRGB(25, 25, 25) popup.BackgroundTransparency = 0 popup.BorderSizePixel = 0 popup.ZIndex = 10 popup.Visible = true popup.Parent = gui addCornerBrackets(popup, rolledItem.color or Color3.fromRGB(200, 200, 200)) local nameLabel = Instance.new("TextLabel") nameLabel.Name = "ItemName" nameLabel.Size = UDim2.new(0.9, 0, 0.3, 0) nameLabel.Position = UDim2.new(0.05, 0, 0.15, 0) nameLabel.BackgroundTransparency = 1 nameLabel.Font = Enum.Font.Arcade nameLabel.Text = rolledItem.name nameLabel.TextColor3 = rolledItem.color nameLabel.TextStrokeTransparency = 0.3 nameLabel.TextStrokeColor3 = Color3.fromRGB(0, 0, 0) nameLabel.TextScaled = true nameLabel.ZIndex = popup.ZIndex + 1 nameLabel.Visible = true nameLabel.Parent = popup local oddsLabel = Instance.new("TextLabel") oddsLabel.Name = "ItemOdds" oddsLabel.Size = UDim2.new(0.9, 0, 0.15, 0) oddsLabel.Position = UDim2.new(0.05, 0, 0.45, 0) oddsLabel.BackgroundTransparency = 1 oddsLabel.Font = Enum.Font.Arcade