RGB(60, 25, 25) skipBtn.BackgroundTransparency = 0 skipBtn.BorderSizePixel = 0 skipBtn.Font = Enum.Font.Arcade skipBtn.Text = "Skip" skipBtn.TextColor3 = Color3.fromRGB(255, 255, 255) skipBtn.TextStrokeTransparency = 0.3 skipBtn.TextStrokeColor3 = Color3.fromRGB(0, 0, 0) skipBtn.TextScaled = true skipBtn.ZIndex = buttonContainer.ZIndex + 1 skipBtn.Visible = true skipBtn.Parent = buttonContainer addCornerBrackets(skipBtn, Color3.fromRGB(200, 100, 100)) local function cleanupRoll() isRolling = false if popup and popup.Parent then popup:Destroy() end end local function doEquip() playGuiClickSound() local success = addToInventory(rolledItem.name) if success then equipBtn.Text = "Added!" equipBtn.BackgroundColor3 = Color3.fromRGB(50, 120, 50) else equipBtn.Text = "Failed!" equipBtn.BackgroundColor3 = Color3.fromRGB(120, 50, 50) end wait(0.3) cleanupRoll() end local function doSkip() playGuiClickSound() skipBtn.Text = "Skipped!" skipBtn.BackgroundColor3 = Color3.fromRGB(120, 50, 50) wait(0.3) cleanupRoll() end equipBtn.Activated:Connect(doEquip) skipBtn.Activated:Connect(doSkip) if autoAction == "equip" then spawn(function() wait(0.6) if equipBtn and equipBtn.Parent then doEquip() end end) elseif autoAction == "skip" then spawn(function() wait(0.6) if skipBtn and skipBtn.Parent then doSkip() end end) end print("?? Roll Popup: Final popup shown for " .. rolledItem.name .. (autoAction and (" (auto: " .. autoAction .. ")") or "")) end local function rollForItem() local totalWeight = 0 for _, item in pairs(brainrotItems) do totalWeight = totalWeight + (1000 / item.odds) end local randomValue = math.random() * totalWeight local currentWeight = 0 for _, item in pairs(brainrotItems) do currentWeight = currentWeight + (1000 / item.odds) if randomValue <= currentWeight then return item end end return brainrotItems[1] end local function getRareBrainrot() local rares = {} for _, item in pairs(brainrotItems) do if item.rarity == "rare" or item.rarity == "mythic" or item.rarity == "le