sLuckBoost() local totalBoost = 0 if checkGamepassOwnership(PREMIUM_LUCK_GAMEPASS_ID) then totalBoost = totalBoost + 100 print("?? Player has premium luck gamepass: +100%") end if checkGamepassOwnership(LUCK_BOOST_GAMEPASS_ID) then totalBoost = totalBoost + 25 print("?? Player has standard luck gamepass: +25%") end return totalBoost end refreshGamepassLuck = function() spawn(function() local newGamepassBoost = calculateGamepassLuckBoost() if newGamepassBoost ~= gamepassLuckBoost then gamepassLuckBoost = newGamepassBoost updateLastKnownState(badgeLuckBoost, gamepassLuckBoost, potionLuckBoost) if updateLuckDisplay then updateLuckDisplay() end if createLuckGlow then createLuckGlow() end print("?? ? Gamepass luck boost updated to: +" .. gamepassLuckBoost .. "%") end end) end local function cleanupConnections() for i, connection in ipairs(connections) do if connection then connection:Disconnect() end end connections = {} end local function addCornerBrackets(parent, color) local thickness = 1 local length = 8 for _, child in pairs(parent:GetChildren()) do if child.Name:find("Bracket") then child:Destroy() end end local brackets = { {name = "BracketTL1", size = UDim2.new(0, length, 0, thickness), pos = UDim2.new(0, 0, 0, 0)}, {name = "BracketTL2", size = UDim2.new(0, thickness, 0, length), pos = UDim2.new(0, 0, 0, 0)}, {name = "BracketTR1", size = UDim2.new(0, length, 0, thickness), pos = UDim2.new(1, -length, 0, 0)}, {name = "BracketTR2", size = UDim2.new(0, thickness, 0, length), pos = UDim2.new(1, -thickness, 0, 0)}, {name = "BracketBL1", size = UDim2.new(0, length, 0, thickness), pos = UDim2.new(0, 0, 1, -thickness)}, {name = "BracketBL2", size = UDim2.new(0, thickness, 0, length), pos = UDim2.new(0, 0, 1, -length)}, {name = "BracketBR1", size = UDim2.new(0, length, 0, thickness), pos = UDim2.new(1, -length, 1, -thickness)}, {name = "BracketBR2", size = UDim2.new(0, thickness, 0, length), pos = UDim2.new(1, -thickness, 1, -length)} } for _, bracket in ipairs(brackets) do local frame = Instance.new("Frame") frame.Name = bracket.name frame.Size = bracket.size frame.Position = bracket.pos frame.BackgroundColor3 = color frame.BorderSizePixel = 0 frame.Parent = parent end end local function getTotalLuckBoost() local gearMultiplier = 1 + (badgeLuckBoost / 100) local gamepassMultiplier = 1 + (gamepassLuckBoost / 100) local potionMultiplier = 1 + (potionLuckBoost / 100) local totalMultiplier = currentLuckBoost * gearMultiplier * gamepassMultiplier * potionMultiplier return totalMultiplier end updateLuckDisplay = function() if not gui or not gui.Parent then return end if not tooltipRollValue or not tooltipRollValue.Parent or not tooltipGearValue or not tooltipGearValue.Parent or not tooltipGamepassValue or not tooltipGamepassValue.Parent or not tooltipPotionValue or not tooltipPotionValue.Parent or not tooltipTotalValue or not tooltipTotalValue.Parent or not tooltipDesc or not tooltipDesc.Parent or not tooltipTitle or not tooltipTitle.Parent or not luckDecal or not luckDecal.Parent then return end local totalLuckBoost = getTotalLuckBoost() tooltipRollValue.Text = "Roll: " .. currentLuckBoost .. "x" tooltipGearValue.Text = "Gears: +" .. badgeLuckBoost .. "%" if gamepassLuckBoost > 0 then tooltipGamepassValue.Text = "Gamepass: +" .. gamepassLuckBoost .. "%" tooltipGamepassValue.TextColor3 = Color3.fromRGB(255, 215, 0) else tooltipGamepassValue.Text = "Gamepass: +0%" tooltipGamepassValue.TextColor3 = Color3.fromRGB(150, 150, 150) end tooltipPotionValue.Text = "Potion: +" .. potionLuckBoost .. "%" tooltipTotalValue.Text = string.format("Total: %.2fx", totalLuckBoost) local newColor local newBracketColor if totalLuckBoost >= 10 then newColor = Color3.fromRGB(255, 0, 255) newBracketColor = Color3.fromRGB(255, 0, 255) tooltipTitle.TextColor3 = Color3.fromRGB(255, 0, 255) tooltipTotalValue.TextColor3 = Color3.fromRGB(255, 0, 255) tooltipDesc.Text = "GODLIKE boost!" tooltipDesc.TextColor3 = Color3.fromRGB(255, 0, 255) elseif totalLuckBoost >= 8 then newColor = Color3.fromRGB(255, 100, 255) newBracketColor = Color3.fromRGB(255, 100, 255) tooltipTitle.TextColor3 = Color3.fromRGB(255, 100, 255) tooltipTotalValue.TextColor3 = Color3.fromRGB(255, 100, 255) tooltipDesc.Text = "INSANE boost!" tooltipDesc.TextColor3 = Color3.fromRGB(255, 100, 255) elseif totalLuckBoost >= 5 then newColor = Color3.fromRGB(255, 150, 0) newBracketColor = Color3.fromRGB(255, 150, 0) tooltipTitle.TextColor3 = Color3.fromRGB(255, 150, 0) tooltipTotalValue.TextColor3 = Color3.fromRGB(255, 150, 0) tooltipDesc.Text = "HIGH boost!" tooltipDesc.TextColor3 = Color3.fromRGB(255, 150, 0) elseif totalLuckBoost >= 3 then newColor = Color3.fromRGB(255, 215, 0) newBracketColor = Color3.fromRGB(255, 215, 0) tooltipTitle.TextColor3 = Color3.fromRGB(255, 215, 0) tooltipTotalValue.TextColor3 = Color3.fromRGB(255, 215, 0) tooltipDesc.Text = "GREAT boost!" tooltipDesc.TextColor3 = Color3.fromRGB(255, 215, 0) elseif totalLuckBoost > 1 or badgeLuckBoost > 0 or gamepassLuckBoost > 0 or potionLuckBoost > 0 then newColor = Color3.fromRGB(100, 255, 100) newBracketColor = Color3.fromRGB(100, 255, 100) tooltipTitle.TextColor3 = Color3.fromRGB(100, 255, 100) tooltipTotalValue.TextColor3 = Color3.fromRGB(100, 255, 100) tooltipDesc.Text = "Better odds" tooltipDesc.TextColor3 = Color3.fromRGB(100, 255, 100) else newColor = Color3.fromRGB(200, 200, 200) newBracketColor = Color3.fromRGB(200, 200, 200) tooltipTitle.TextColor3 = Color3.fromRGB(200, 200, 200) tooltipTotalValue.TextColor3 = Color3.fromRGB(200, 200, 200) tooltipDesc.Text = "No boost" tooltipDesc.TextColor3 = Color3.fromRGB(150, 150, 150) end luckDecal.ImageColor3 = newColor addCornerBrackets(luckContainer, newBracketColor) addCornerBrackets(tooltip, newBracketColor) end createLuckGlow = function() if not luckContainer or not luckContainer.Parent or not luckDecal then return end local totalLuckBoost = getTotalLuckBoost() if totalLuckBoost <= 1 and badgeLuckBoost <= 0 and gamepassLuckBoost <= 0 and potionLuckB